#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin>>n;
    int a[n],b[n],c[n],z[n],s=0;
    for(int i=0;i<n;i++){
        cin>>a[i]>>b[i]>>c[i];
        z[i]=a[i]+b[i]+c[i];
    }
    for(int i=0;i<n-1;i++){
        for(int j=i+1;j<n;j++){
            if((abs(a[i]-a[j])<=5)&&abs(b[i]-b[j])<=5&&abs(c[i]-c[j])<=5&&abs(z[i]-z[j])<=10){
                s++;
            }
        }
    }
    cout<<s;
    return 0;
}
